const b = ($input.first() && $input.first().json && $input.first().json.body) || {};
let slugs = Array.isArray(b.slugs) ? b.slugs : [];
slugs = slugs.map(s => String(s || '').trim()).filter(s => /^[A-Za-z0-9&_-]{1,80}$/.test(s));
slugs = [...new Set(slugs)].slice(0, 80);
if (!slugs.length) throw new Error('slugs[] required in POST body');
return [{ json: { slugs } }];

const want = $('Validate Slugs').first().json.slugs;
const resp = $input.first().json || {};
const titles = new Set(((resp.sheets || []).map(s => (s.properties || {}).title)).filter(Boolean));
const present = want.filter(s => titles.has('Calendar_' + s));
const missing = want.filter(s => !titles.has('Calendar_' + s));
if (!present.length) return [{ json: { skip: true, present, missing } }];
const ranges = present.map(s => 'ranges=' + encodeURIComponent("'Calendar_" + s + "'"));
const url = 'https://sheets.googleapis.com/v4/spreadsheets/1Gsn5xLImJyMhBMCNjK_tigpoUfcSFnvxTQLkk-A9Yps/values:batchGet?' + ranges.join('&') + '&valueRenderOption=UNFORMATTED_VALUE&dateTimeRenderOption=FORMATTED_STRING&majorDimension=ROWS';
return [{ json: { skip: false, url, present, missing } }];

const meta = $('Build BatchGet URL').first().json;
const resp = $input.first().json || {};
const clients = {};
for (const vr of (resp.valueRanges || [])) {
  const m = String(vr.range || '').match(/^'?Calendar_([^'!]+)'?!/);
  if (!m) continue;
  const slug = m[1];
  const values = vr.values || [];
  if (!values.length) { clients[slug] = { posts: [] }; continue; }
  const headers = values[0].map(h => String(h || '').trim());
  const posts = [];
  for (let i = 1; i < values.length; i++) {
    const row = values[i] || [];
    const obj = {};
    for (let c = 0; c < headers.length; c++) { if (headers[c]) obj[headers[c]] = row[c] !== undefined ? row[c] : ''; }
    if (obj.id) posts.push(obj);
  }
  posts.sort((a, b) => Number(a.order_index || 0) - Number(b.order_index || 0));
  clients[slug] = { posts };
}
for (const s of (meta.present || [])) { if (!clients[s]) clients[s] = { posts: [] }; }
return [{ json: { ok: true, clients, missing: meta.missing || [] } }];
